template:
const std = @import("std");

pub const Circle = struct {
    radius: f64,
};

pub const Rectangle = struct {
    width: f64,
    height: f64,
};

pub const Square = struct {
    side: f64,
};

pub const Shape = [[SLOT union_kw]] {
    circle: Circle,
    rectangle: Rectangle,
    square: Square,
};

pub fn area(shape: Shape) f64 {
    return switch (shape) {
        .circle => |c| [[SLOT circle_area]],
        .rectangle => |r| [[SLOT rect_area]],
        .square => |s| [[SLOT square_area]],
    };
}
